#include <bits/stdc++.h>
using namespace std;

const int N=3e4+10,INF=0x3f3f3f3f;

struct Edge{
    int to,val;
};

bool operator<(Edge x,Edge y){
    return x.val>y.val;
}

int n,r,p,st,c[N],dis[N],deg[N],cnt;
bool b[N];
vector<Edge> g[N];
vector<int> num[N];
priority_queue<Edge> q;
queue<int> s;

void dfs(int x,int col){
    c[x]=col,num[col].push_back(x);
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(!c[g[x][i].to])
            dfs(g[x][i].to,col);
}

int main(){
    scanf("%d%d%d%d",&n,&r,&p,&st);
    for(int i=0,u,v,w;i<r;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        g[v].push_back({u,w});
    }
    for(int i=1;i<=n;i++)
        if(!c[i])
            dfs(i,++cnt);
    for(int i=0,u,v,w;i<p;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back({v,w});
        deg[c[v]]++;
    }
    for(int i=1;i<=cnt;i++)
        if(c[st]==i || deg[i]==0)
            s.push(i);
    memset(dis,0x3f,sizeof(dis));
    dis[st]=0;
    while(s.size()){
        int x=s.front(),len=num[x].size();
        s.pop();
        for(int i=0;i<len;i++)
            q.push({num[x][i],dis[num[x][i]]});
        while(q.size()){
            while(q.size() && b[q.top().to])
                q.pop();
            if(q.empty())
                break;
            int u=q.top().to,len=g[u].size();
            q.pop(),b[u]=1;
            for(int i=0;i<len;i++){
                if(dis[g[u][i].to]>dis[u]+g[u][i].val && !b[g[u][i].to]){
                    if(dis[u]!=INF)
                        dis[g[u][i].to]=dis[u]+g[u][i].val;
                    if(c[g[u][i].to]==c[u])
                        q.push({g[u][i].to,dis[g[u][i].to]});
                }
                if(c[g[u][i].to]!=c[u]){
                    deg[c[g[u][i].to]]--;
                    if(deg[c[g[u][i].to]]==0)
                        s.push(c[g[u][i].to]);
                }
                //不要忘了做拓扑序
            }
        }
    }
    for(int i=1;i<=n;i++){
        if(dis[i]==INF)
            puts("NO PATH");
        else
            printf("%d\n",dis[i]);
    }
    return 0;
}
